/**
 * THE ADAPTER CONTRACT. This file IS the spec src/store.ts implements
 * against — read it fully before touching store.ts.
 *
 * WHAT THIS INTERFACE DELIBERATELY DOES NOT HAVE: any payment method, any
 * order-creation method, any customer/admin method. That absence is this
 * server's entire payment/order boundary — see getCheckoutUrl's own doc
 * comment below. This interface intentionally cannot express payment
 * authorization. If you find yourself needing to add such a method here,
 * STOP — that is outside this server's scope. Payment and order placement
 * belong on your own checkout page, reached via the URL getCheckoutUrl()
 * returns, never in this adapter.
 */

export interface Product {
  id: string;
  title: string;
  description: string;
  /** A decimal amount as a string, e.g. "19.99" — no currency symbol. */
  price: string;
  /** ISO 4217 currency code, e.g. "USD". */
  currency: string;
  inStock: boolean;
  /** Link to this product's page on your store, if it has one. Optional. */
  url?: string;
}

export interface CartLineItem {
  /** A stable id for THIS LINE ITEM — not the product id. Returned by
   *  addToCart, then used by updateCartItem/removeCartItem to identify
   *  which line to change. If your cart layer doesn't have a natural line
   *  item id, the product id is an acceptable stand-in ONLY if a cart can
   *  never hold the same product twice as separate lines. */
  id: string;
  productId: string;
  title: string;
  quantity: number;
  /** This line's unit price, same format as Product.price. */
  price: string;
}

export interface Cart {
  id: string;
  lineItems: CartLineItem[];
  currency: string;
  /** The cart's total, if your store can compute one cheaply. Optional —
   *  callers should sum lineItems themselves if this is omitted. */
  total?: string;
}

/**
 * The eight methods server.ts (complete, do not edit) calls and nothing
 * else. Implement each against your own store's product/cart layer — see
 * src/store.ts for a stub of every method with a worked example.
 */
export interface StoreAdapter {
  /** Return up to `limit` products matching `query`. Return an empty
   *  array for "no results" — never throw for that case. */
  searchProducts(query: string, limit: number): Promise<Product[]>;
  /** Return full details for one product by id. Throw a real Error (any
   *  message) if the id doesn't exist. */
  getProduct(id: string): Promise<Product>;
  /** Return the current shopper's cart. If none exists yet, return an
   *  empty one (lineItems: []) — that's a normal state, not an error. */
  getCart(): Promise<Cart>;
  /** Add `quantity` of product `productId` to the cart (creating the cart
   *  if needed) and return the resulting cart. */
  addToCart(productId: string, quantity: number): Promise<Cart>;
  /** Change the quantity of the cart line item `lineItemId` (NOT a product
   *  id — see CartLineItem.id above) and return the resulting cart. */
  updateCartItem(lineItemId: string, quantity: number): Promise<Cart>;
  /** Remove the cart line item `lineItemId` and return the resulting cart. */
  removeCartItem(lineItemId: string): Promise<Cart>;
  /** Remove EVERY line item from the cart — a real, total removal (not a
   *  session-state flag). Used both to guarantee a truly empty starting
   *  cart and to make cart cancellation genuine, not just pretended. Return
   *  the resulting (now empty) cart. */
  emptyCart(): Promise<Cart>;
  /**
   * Return a URL where the shopper completes their purchase on YOUR store's
   * own checkout, for the current cart.
   *
   * This method must NOT authorize, capture, or process payment. Return a
   * URL where the shopper completes payment on your own checkout, exactly
   * as they would normally — the same URL you'd hand a shopper who filled a
   * cart on your website directly. Do not collect card details, call a
   * payment processor, or create a completed order in this method.
   */
  getCheckoutUrl(): Promise<string>;
}

