import type { StoreAdapter, Product, Cart } from "./types.js";

/**
 * THE INTEGRATION POINT. Every method below throws a placeholder error —
 * that's intentional: this scaffold cannot know your store's stack, so it
 * cannot generate a working client for it. Replace each throw with real
 * code against your own store's product/cart layer. See README.md for the
 * recommended implementation order and how to test each method alone.
 *
 * A plain object implementing StoreAdapter (not a class) — call these
 * directly, e.g. `await storeAdapter.getProduct("123")`, to test one
 * method at a time before wiring up the full server.
 */
export const storeAdapter: StoreAdapter = {
  /**
   * Expected return shape:
   *   [{ id: "123", title: "Blue T-Shirt", description: "100% cotton",
   *      price: "19.99", currency: "USD", inStock: true,
   *      url: "https://yourstore.example.com/products/123" }]
   */
  async searchProducts(query: string, limit: number): Promise<Product[]> {
    /* Example (generic REST) — replace this ENTIRE function body with real
     * code; this comment block is guidance, not a working implementation:
     *
     *   const res = await fetch(
     *     `${process.env.STORE_BASE_URL}/api/products?q=${encodeURIComponent(query)}&limit=${limit}`,
     *   );
     *   const data = await res.json();
     *   return data.products.map((p: any) => ({
     *     id: String(p.id),
     *     title: p.name,
     *     description: p.description ?? "",
     *     price: String(p.price),
     *     currency: p.currency ?? "USD",
     *     inStock: p.stock_quantity > 0,
     *     url: p.url,
     *   }));
     *
     * The same fetch-your-API-then-map-to-the-contract pattern applies to
     * every method below — it isn't repeated for each one.
     */
    throw new Error(
      "IMPLEMENT-THIS: return up to 'limit' products matching 'query' from your store's catalog. Never throw for zero results — return []. See this method's doc comment above and src/types.ts's Product type for the exact shape.",
    );
  },

  /**
   * Expected return shape: a single Product object (see searchProducts'
   * example above for the field shape). Throw a real Error if `id` doesn't
   * exist in your catalog.
   */
  async getProduct(id: string): Promise<Product> {
    throw new Error(
      "IMPLEMENT-THIS: return full details for the product with this id, or throw if it doesn't exist. See src/types.ts's Product type for the exact shape.",
    );
  },

  /**
   * Expected return shape:
   *   { id: "cart_abc", lineItems: [], currency: "USD" }
   * for an empty/new cart, or with real CartLineItem entries once
   * populated. Return an empty cart rather than throwing when none exists.
   */
  async getCart(): Promise<Cart> {
    throw new Error(
      "IMPLEMENT-THIS: return the current cart, or an empty one (lineItems: []) if none exists yet — never throw for that case. See src/types.ts's Cart type for the exact shape.",
    );
  },

  /** Add `quantity` of product `productId` to the cart (creating the cart
   *  if it doesn't exist yet) and return the resulting Cart. */
  async addToCart(productId: string, quantity: number): Promise<Cart> {
    throw new Error(
      "IMPLEMENT-THIS: add 'quantity' of product 'productId' to the cart (creating it if needed) and return the resulting cart. See src/types.ts's Cart type for the exact shape.",
    );
  },

  /** Change the quantity of cart line item `lineItemId` (NOT a product id
   *  — see CartLineItem.id in src/types.ts) and return the resulting Cart. */
  async updateCartItem(lineItemId: string, quantity: number): Promise<Cart> {
    throw new Error(
      "IMPLEMENT-THIS: change the quantity of the cart line item 'lineItemId' and return the resulting cart. See src/types.ts's CartLineItem type — 'lineItemId' is a LINE ITEM id, not a product id.",
    );
